SELECT u.user_id, u.realname, u.img, u.dept_id, d.dept_name, u.post, u.mobile, u.email, u.employee_status, ( SELECT MAX(COALESCE(t.completed_time, t.due_date, t.update_time, t.create_time)) FROM crm_task t WHERE t.assigned_to = u.user_id ) AS recent_task_time FROM manager_user u LEFT JOIN manager_dept d ON u.dept_id = d.dept_id WHERE 1 = 1
AND 1 = 1
AND u.user_id IN
#{userId}
AND 1 = 0
AND ( u.realname LIKE CONCAT('%', #{query.keyword}, '%') OR u.mobile LIKE CONCAT('%', #{query.keyword}, '%') OR u.email LIKE CONCAT('%', #{query.keyword}, '%') OR u.post LIKE CONCAT('%', #{query.keyword}, '%') OR d.dept_name LIKE CONCAT('%', #{query.keyword}, '%') )
AND u.dept_id IN
#{deptId}
AND u.employee_status = #{query.employeeStatus}
ORDER BY CASE COALESCE(u.employee_status, 'active') WHEN 'active' THEN 0 WHEN 'disabled' THEN 1 WHEN 'resigned' THEN 2 ELSE 3 END, u.create_time DESC
